/**
 * Vendored by the Starwind CLI.
 * You own this file in your project.
 */
import type { HTMLAttributes } from "astro/types";

interface Props extends Omit<
  HTMLAttributes<"button">,
  "aria-pressed" | "defaultPressed" | "disabled" | "onChange" | "type" | "value"
> {
  defaultPressed?: boolean;
  disabled?: boolean;
  nativeButton?: boolean;
  pressed?: boolean;
  syncGroup?: string;
  value?: string;
}

const {
  defaultPressed = false,
  disabled = false,
  nativeButton = true,
  pressed,
  syncGroup,
  value,
  ...rest
} = Astro.props;

const Tag = nativeButton ? "button" : "span";
const initialPressed = pressed ?? defaultPressed;
const defaultPressedAttribute = pressed === undefined && defaultPressed ? "true" : undefined;
---

<Tag
  {...rest}
  data-sw-toggle
  data-default-pressed={defaultPressedAttribute}
  data-native={!nativeButton ? "false" : undefined}
  data-sync-group={syncGroup}
  data-value={value}
  aria-disabled={!nativeButton && disabled ? "true" : undefined}
  aria-pressed={initialPressed ? "true" : "false"}
  data-disabled={disabled ? "" : undefined}
  data-pressed={initialPressed ? "" : undefined}
  data-state={initialPressed ? "on" : "off"}
  data-unpressed={!initialPressed ? "" : undefined}
  disabled={nativeButton && disabled ? true : undefined}
  role={!nativeButton ? "button" : undefined}
  tabindex={!nativeButton ? (disabled ? -1 : 0) : undefined}
  type={nativeButton ? "button" : undefined}
  value={nativeButton ? value : undefined}
>
  <slot />
</Tag>

<script>
  import { createToggle } from "@starwind-ui/runtime/toggle";
  import { registerAstroControllerLifecycle } from "../internal/controller-lifecycle";

  const toggleInstances = new Set<ReturnType<typeof createToggle>>();

  const getInitCandidates = (event: Event | undefined, selector: string): HTMLElement[] => {
    const initRoot =
      event?.type === "starwind:init" && event instanceof CustomEvent
        ? event.detail?.root
        : undefined;
    const scopedRoot: Document | DocumentFragment | Element = isQueryableRoot(initRoot)
      ? initRoot
      : document;
    const candidates = Array.from(scopedRoot.querySelectorAll<HTMLElement>(selector));

    if (scopedRoot instanceof Element && scopedRoot.matches(selector)) {
      candidates.unshift(scopedRoot as HTMLElement);
    }

    return candidates;
  };

  const isQueryableRoot = (value: unknown): value is Document | DocumentFragment | Element =>
    value instanceof Document || value instanceof DocumentFragment || value instanceof Element;

  const setupToggles = (event?: Event) => {
    getInitCandidates(event, "[data-sw-toggle]").forEach((root) => {
      if (root.hasAttribute("data-sw-theme-toggle")) return;

      toggleInstances.add(createToggle(root));
    });
  };

  const destroyToggles = () => {
    toggleInstances.forEach((instance) => instance.destroy());
    toggleInstances.clear();
  };

  registerAstroControllerLifecycle("ToggleRoot", setupToggles, destroyToggles);
</script>

