  import { createNavigationMenu } from "@starwind-ui/runtime/navigation-menu";
  import { registerAstroControllerLifecycle } from "../internal/controller-lifecycle";

  const navigationMenuInstances = new Set<ReturnType<typeof createNavigationMenu>>();

  const getInitCandidates = (event: Event | undefined, selector: string): HTMLElement[] => {
    const initRoot =
      event?.type === "starwind:init" && event instanceof CustomEvent
        ? event.detail?.root
        : undefined;
