    value instanceof Document || value instanceof DocumentFragment || value instanceof Element;

  const setupNavigationMenus = (event?: Event) => {
    getInitCandidates(event, "[data-sw-nav-menu]").forEach((root) =>
      navigationMenuInstances.add(createNavigationMenu(root)),
    );
  };

  const destroyNavigationMenus = () => {
    navigationMenuInstances.forEach((instance) => instance.destroy());
    navigationMenuInstances.clear();
  };

  registerAstroControllerLifecycle(
    "NavigationMenuRoot",
    setupNavigationMenus,
    destroyNavigationMenus,
  );
